fun solve(nums: Array<Long>): Long {
    val indicesOfOne = mutableListOf<Int>()
    val indicesOfTwo = mutableListOf<Int>()

    for (i in nums.indices) {
        when (nums[i].toInt()) {
            1 -> indicesOfOne.add(i)
            2 -> indicesOfTwo.add(i)
            // 0 is ignored
        }
    }

    if (indicesOfOne.isEmpty() || indicesOfTwo.isEmpty()) {
        return -1L
    }

    var minDiff = Int.MAX_VALUE

    // Since the problem asks for the minimum absolute difference,
    // and we have two sorted lists of indices (because we traversed the array),
    // we can use a two-pointer approach for efficiency, although O(N*M) brute force is fine for N<=100.
    // Let's use the two-pointer approach for robustness.

    var ptr1 = 0
    var ptr2 = 0

    while (ptr1 < indicesOfOne.size && ptr2 < indicesOfTwo.size) {
        val i = indicesOfOne[ptr1]
        val j = indicesOfTwo[ptr2]

        val currentDiff = kotlin.math.abs(i - j)

        if (currentDiff < minDiff) {
            minDiff = currentDiff
        }

        // To potentially find a smaller difference, we move the pointer associated with the smaller index.
        // This brings the next candidate indices closer to each other.
        if (i < j) {
            ptr1++
        } else {
            ptr2++
        }
    }

    return minDiff.toLong()
}
